// PDF入力パラメータの設定
// n8n UIの「Test Workflow」実行前に以下を編集:
const pdf_path = 'C:/Users/y-suz/OneDrive/デスクトップ/ChloeBY展開図‗見積用20251202 2.pdf';
const project_name = 'chloe_by';
const page = 0;

return [{
  json: {
    pdf_path,
    project_name,
    page,
    output_dir: 'C:/Users/y-suz/porano-perse/output',
    scripts_dir: 'C:/Users/y-suz/porano-perse/scripts',
    timestamp: new Date().toISOString()
  }
}];

// マージ済みJSONを読み込んで品質スコアを集計
const fs = require('fs');
const path = require('path');

const input = $input.first().json;
const mergedPath = `${input.output_dir}/blueprint-analysis/${input.project_name}_merged.json`;

let merged;
try {
  merged = JSON.parse(fs.readFileSync(mergedPath, 'utf-8'));
} catch (e) {
  return [{ json: { error: `マージJSONの読み込み失敗: ${e.message}` } }];
}

const score = merged.quality_score || {};
const summary = merged.summary || {};

return [{
  json: {
    ...input,
    quality_score: score,
    summary: summary,
    warnings: merged.warnings || [],
    merged_file: mergedPath,
    dxf_file: `${input.output_dir}/drawings/${input.project_name}_merged.dxf`,
    comparison_file: `${input.output_dir}/drawings/${input.project_name}_merged_comparison.png`,
    status: score.total >= 60 ? 'PASS' : 'NEEDS_REVIEW',
    completed_at: new Date().toISOString()
  }
}];

// ダッシュボード docs/data.js の更新
// 注意: 現在のdata.jsはANALYSIS_DATAのみ。マージ結果で上書きする場合は以下を使用。
// 安全のため、別ファイルに最新結果を書き出す方式を採用。
const fs = require('fs');
const input = $input.first().json;

const dashboardDir = 'C:/Users/y-suz/porano-perse/docs';
const historyFile = `${dashboardDir}/pipeline-history.json`;

// 履歴読み込み (なければ空配列)
let history = [];
try {
  history = JSON.parse(fs.readFileSync(historyFile, 'utf-8'));
} catch (e) {
  history = [];
}

// 今回の結果を追加
history.push({
  project_name: input.project_name,
  pdf_path: input.pdf_path,
  timestamp: input.completed_at,
  quality_score: input.quality_score,
  summary: input.summary,
  warnings: input.warnings,
  status: input.status,
  files: {
    merged_json: input.merged_file,
    dxf: input.dxf_file,
    comparison: input.comparison_file
  }
});

// 最新100件に制限
if (history.length > 100) {
  history = history.slice(-100);
}

fs.writeFileSync(historyFile, JSON.stringify(history, null, 2), 'utf-8');

return [{
  json: {
    ...input,
    dashboard_updated: true,
    history_count: history.length,
    message: `パイプライン完了: ${input.project_name} / スコア: ${input.quality_score.total}/100 / ステータス: ${input.status}`
  }
}];
